// ============================================================================
// SET VIDEO DATA - Consolidate Apify outputs
// ============================================================================
// Combines data from both Apify nodes (downloader + transcript)
// ============================================================================

const formData = $('YouTube URL Form').first().json;
const downloaderData = $('Apify YouTube Downloader').first().json;
const transcriptData = $input.first().json;

// Extract video URL from downloader
// Downloader returns: { sourceUrl, downloadUrl }
const videoUrl = downloaderData.downloadUrl || '';
const sourceUrl = downloaderData.sourceUrl || formData['YouTube URL'];

// Extract video info from transcript node (it has all the metadata)
const videoId = transcriptData.message?.match(/ID '([^']+)'/)?.[1] || sourceUrl.match(/[?&]v=([^&]+)/)?.[1] || '';
const videoTitle = transcriptData.title || 'Unknown Video';
const videoDuration = transcriptData.duration_seconds || 0;
const channelTitle = transcriptData.channel_name || '';
const videoDescription = transcriptData.description;
const channelId = transcriptData.channel_id || '';
const thumbnail = transcriptData.thumbnail || '';
const publishedAt = transcriptData.published_at || '';

// Extract transcript from Apify response
let transcriptText = '';
let transcriptSegments = [];

if (transcriptData.transcript && Array.isArray(transcriptData.transcript)) {
  // Apify returns array of {text, start, duration}
  transcriptSegments = transcriptData.transcript.map((seg, index) => ({
    index,
    text: seg.text || '',
    start: seg.start || 0,
    end: (seg.start || 0) + (seg.duration || 0),
    start_formatted: formatTime(seg.start || 0),
    end_formatted: formatTime((seg.start || 0) + (seg.duration || 0))
  }));
  transcriptText = transcriptSegments.map(s => s.text).join(' ');
}

function formatTime(seconds) {
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins}:${secs.toString().padStart(2, '0')}`;
}

return [{
  json: {
    // Source info
    youtube_url: sourceUrl,
    video_id: videoId,
    video_name: videoTitle,
    video_url: videoUrl,
    channel_title: channelTitle,
    channel_id: channelId,
    thumbnail: thumbnail,
    published_at: publishedAt,

    // Duration
    duration: videoDuration,
    duration_formatted: formatTime(videoDuration),
    description: videoDescription,

    // Transcript data
    transcript_text: transcriptText,
    segments: transcriptSegments,
    segment_count: transcriptSegments.length,

    // Extra metadata from transcript node
    like_count: transcriptData.like_count || 0,
    comment_count: transcriptData.comment_count || 0,
    subscriber_count: transcriptData.subscriber_count || 0,
    is_auto_generated: transcriptData.is_auto_generated || false,

    // Metadata
    timestamp: new Date().toISOString()
  }
}];

// ============================================================================
// PARSE KEY ACTIONS v4.0 (Webcam Crop Support)
// ============================================================================
// - Parses Gemini response with new webcam detection schema
// - Filters out talking-head-only clips (no usable screen content)
// - KEEPS webcam overlay clips that have usable screen content + crop data
// - Categorizes clips for downstream Creatomate processing
// ============================================================================

const geminiOutput = $input.first().json;
const videoData = $('Set Video Data').first().json;

// ============================================================================
// PARSE GEMINI RESPONSE
// ============================================================================

let keyMoments = [];
let responseText = '';

try {
  // Handle different Gemini response structures
  if (Array.isArray(geminiOutput)) {
    responseText = geminiOutput[0]?.content?.parts?.[0]?.text || '';
  } else if (geminiOutput.content?.parts) {
    responseText = geminiOutput.content.parts[0]?.text || '';
  } else if (typeof geminiOutput === 'string') {
    responseText = geminiOutput;
  } else if (geminiOutput.text) {
    responseText = geminiOutput.text;
  } else if (geminiOutput.output) {
    const output = geminiOutput.output;
    if (Array.isArray(output) && output[0]?.content?.parts) {
      responseText = output[0].content.parts[0]?.text || '';
    } else if (Array.isArray(output) && output[0]?.content) {
      responseText = output[0].content[0]?.text || JSON.stringify(output);
    } else {
      responseText = typeof output === 'string' ? output : JSON.stringify(output);
    }
  } else {
    responseText = JSON.stringify(geminiOutput);
  }

  // Clean markdown formatting
  responseText = responseText
    .replace(/```json\n?/gi, '')
    .replace(/```\n?/gi, '')
    .trim();

  keyMoments = JSON.parse(responseText);

  if (!Array.isArray(keyMoments)) {
    throw new Error('Response is not a JSON array');
  }

} catch (parseError) {
  throw new Error(`FATAL: Failed to parse Gemini response - ${parseError.message}`);
}

// ============================================================================
// VALIDATE: Must have at least 1 clip
// ============================================================================

if (keyMoments.length === 0) {
  throw new Error('FATAL: Gemini returned 0 key moments. Video may not contain usable B-roll.');
}

console.log(`✓ Parsed ${keyMoments.length} key moments from Gemini`);

// ============================================================================
// CATEGORIZE CLIPS BY USABILITY
// ============================================================================

const totalClips = keyMoments.length;

// Category 1: Clean screen recordings (no person visible)
const cleanScreenClips = keyMoments.filter(m => m.person_visible !== true);

// Category 2: Webcam overlay clips WITH usable screen content (can be cropped)
const webcamOverlayClips = keyMoments.filter(m => 
  m.person_visible === true && 
  m.has_usable_screen_content === true &&
  m.safe_crop_zone !== null &&
  m.creatomate_crop !== null
);

// Category 3: Talking head only (NOT usable - will be filtered out)
const talkingHeadClips = keyMoments.filter(m => 
  m.person_visible === true && 
  (m.has_usable_screen_content === false || m.has_usable_screen_content === undefined)
);

// Category 4: Webcam overlay but MISSING crop data (unusable due to incomplete data)
const incompleteWebcamClips = keyMoments.filter(m =>
  m.person_visible === true &&
  m.has_usable_screen_content === true &&
  (m.safe_crop_zone === null || m.creatomate_crop === null)
);

console.log(`📊 Clip Categorization:`);
console.log(`   - Clean screen recordings: ${cleanScreenClips.length}`);
console.log(`   - Webcam overlay (croppable): ${webcamOverlayClips.length}`);
console.log(`   - Talking head only (filtered): ${talkingHeadClips.length}`);
console.log(`   - Incomplete webcam data (filtered): ${incompleteWebcamClips.length}`);

// ============================================================================
// COMBINE USABLE CLIPS
// ============================================================================

// Usable clips = clean screen + webcam overlay with valid crop data
const usableClips = [...cleanScreenClips, ...webcamOverlayClips];

// Sort by start_seconds to maintain chronological order
usableClips.sort((a, b) => (a.start_seconds || 0) - (b.start_seconds || 0));

// Add processing metadata to each clip
const processedClips = usableClips.map((clip, index) => ({
  ...clip,
  // Add processing flags
  _processing: {
    clip_index: index,
    requires_crop: clip.person_visible === true && clip.has_usable_screen_content === true,
    crop_strategy: clip.safe_crop_zone?.strategy || null,
    content_preserved_percent: clip.safe_crop_zone?.content_preserved_percent || 100
  }
}));

const filteredOutCount = talkingHeadClips.length + incompleteWebcamClips.length;
const clipsRequiringCrop = processedClips.filter(c => c._processing.requires_crop).length;

console.log(`✓ Total usable clips: ${processedClips.length}`);
console.log(`✓ Clips requiring crop: ${clipsRequiringCrop}`);
console.log(`✓ Clips filtered out: ${filteredOutCount}`);

// ============================================================================
// VALIDATE: Must have clips AFTER filtering
// ============================================================================

if (processedClips.length === 0) {
  const errorDetails = [
    `Total clips from Gemini: ${totalClips}`,
    `Talking head clips (no screen content): ${talkingHeadClips.length}`,
    `Webcam clips with missing crop data: ${incompleteWebcamClips.length}`,
    `Clean screen clips: ${cleanScreenClips.length}`,
    `Croppable webcam clips: ${webcamOverlayClips.length}`
  ].join('. ');

  throw new Error(`FATAL: No usable B-roll clips after filtering. ${errorDetails}`);
}

// ============================================================================
// QUICK STATS
// ============================================================================

const uniqueApps = [...new Set(processedClips.map(m => m.app).filter(Boolean))];
const totalDuration = processedClips.reduce((sum, m) => {
  return sum + ((m.end_seconds || 0) - (m.start_seconds || 0));
}, 0);

// Webcam position distribution (for clips that have webcam)
const webcamPositions = webcamOverlayClips.reduce((acc, clip) => {
  const pos = clip.webcam_region?.position || 'unknown';
  acc[pos] = (acc[pos] || 0) + 1;
  return acc;
}, {});

console.log(`Apps detected: ${uniqueApps.join(', ') || 'none'}`);
console.log(`Total action time: ${totalDuration.toFixed(0)}s`);
if (Object.keys(webcamPositions).length > 0) {
  console.log(`Webcam positions: ${JSON.stringify(webcamPositions)}`);
}

// ============================================================================
// RETURN
// ============================================================================

return [{
  json: {
    youtube_url: videoData.youtube_url,
    video_id: videoData.video_id,
    video_name: videoData.video_name,
    video_url: videoData.video_url,
    videoDescription: videoData.description,
    channel_title: videoData.channel_title,
    transcript_text: videoData.transcript_text,
    duration: videoData.duration,
    segments: videoData.segments,
    key_moments: processedClips,
    visual_analysis: {
      // Counts
      total_from_gemini: totalClips,
      usable_clips_count: processedClips.length,
      clean_screen_clips: cleanScreenClips.length,
      webcam_overlay_clips: webcamOverlayClips.length,
      clips_requiring_crop: clipsRequiringCrop,

      // Filtered out
      filtered_out_total: filteredOutCount,
      filtered_talking_head: talkingHeadClips.length,
      filtered_incomplete_data: incompleteWebcamClips.length,

      // Metadata
      unique_apps: uniqueApps,
      webcam_positions: webcamPositions,
      total_action_time_seconds: totalDuration,
      video_duration_seconds: videoData.duration,
      analyzed_at: new Date().toISOString()
    }
  }
}];

